18.5 MCMC Sampling for PK Parameters

18.5.1 Using Stan via cmdstanr


Code
library(cmdstanr)

# Stan model for one-compartment IV bolus
stan_code &lt;- "
data {
  int&lt;lower=0&gt; N;
  array[N] real time;
  array[N] real conc;
  real dose;
}
parameters {
  real&lt;lower=0&gt; CL;
  real&lt;lower=0&gt; V;
  real&lt;lower=0&gt; sigma;
}
transformed parameters {
  real ke = CL / V;
  array[N] real conc_pred;
  for (i in 1:N) {
    conc_pred[i] = (dose / V) * exp(-ke * time[i]);
  }
}
model {
  // Priors
  CL ~ lognormal(log(4), 0.5);
  V  ~ lognormal(log(40), 0.3);
  sigma ~ normal(0, 2);

  // Likelihood
  conc ~ lognormal(log(conc_pred), sigma);
}
"

# Compile and sample
# mod &lt;- cmdstan_model(write_stan_file(stan_code))
# fit &lt;- mod$sample(
#   data = list(N = nrow(obs_data), time = obs_data$time,
#               conc = obs_data$conc, dose = dose),
#   seed = 123, chains = 4, parallel_chains = 4,
#   iter_warmup = 1000, iter_sampling = 2000
